    class Meta:
        proxy=True

class AaModelForm(ModelForm):
    class Meta:
        model = Bar
        exclude = []

class BbModelForm(ModelForm):
    class Meta:
        model = Bar
        exclude = []

class AaAdminInline(nested_admin.NestedStackedInline):
    model = Aa
    form = AaModelForm
    extra = 1
class BbAdminInline(nested_admin.NestedStackedInline):
    model = Bb
    form = BbModelForm
