It' fair now, since I've made two wrapper classes for ease:

```python
import six
from minio import Minio

class Bucket(object):
    def __init__(self, client, bucket_name):
        self.client = client
        self.bucket_name = bucket_name

    def __repr__(self):
        return '<OSS({}).Bucket({})>'.format(
            self.client._endpoint_url,
            self.bucket_name,
        )

    def ensure(self, **kwargs):
        if not self.client.bucket_exists(self.bucket_name):
            self.client.make_bucket(self.bucket_name, **kwargs)

    def get_object(self, key, **kwargs):
        return self.client.get_object(self.bucket_name, key, **kwargs)

    def put_object(self, key, data,
                   content_type='application/octet-stream',
                   metadata=None,
                   **kwargs):
        """
        Add a new object OSS.

        :param key: Name of new object.
        :param data: Contents to upload, readable or bytes
        """

        assert 'length' not in kwargs, 'I dont care the length!'

        if callable(getattr(data, 'read', None)):
            data = data.read()

        if isinstance(data, six.string_types):
            data = data.encode('utf-8')  # to bytes

        metadata = metadata or {}

        return self.client._do_put_object(
            self.bucket_name, key, data, len(data), **kwargs
        )


class OSSC(Minio):
    """Object Storage Service Client"""

    def bucket(self, bucket_name):
        return Bucket(self, bucket_name)
```

Then I can:

```python
bkt = ossc.bucket('default')

# Write text
text = 'Hello World'
bkt.put_object('hello', text)

# Write bytes
blob = b'Hello World -- bytes'
bkt.put_object('hello', blob)

# Write from file-object
with open('/home/wonder/lab/t.txt', 'r') as f:
    bkt.put_object('hello', f)

# Write BytesIO
buf = io.BytesIO(b'Hello World -- BytesIO')
bkt.put_object('hello', buf)
```

